352:         final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate = new HashMap<>(standbyTasks);
353:         final Map<Task, Set<TopicPartition>> tasksToRecycle = new HashMap<>();
354:         final Set<Task> tasksToCloseClean = new TreeSet<>(Comparator.comparing(Task::id));
